const express = require('express');
const app = express();
app.use(express.json());

app.post('/rappi/webhook', async (req, res) => {
  res.status(200).json({ received: true }); // responder inmediatamente

  const { event_type, order_id } = req.body;

  try {
    switch (event_type) {
      case 'order_created':
        await handleNuevoPedido(req.body);
        break;
      case 'courier_assigned':
        await handleCourierAsignado(req.body);
        break;
      case 'order_finished':
        await handlePedidoFinalizado(req.body);
        break;
    }
  } catch (err) {
    console.error(`Error procesando ${order_id}:`, err);
  }
});

async function handleNuevoPedido(payload) {
  if (await db.pedidoExiste(payload.order_id)) return; // idempotencia
  await db.guardarPedido(payload);
  await erpClient.crearPedido(payload);
  await notificarEquipoPicking(payload.order_id);
}

